package com.nexters.external.service

import com.google.genai.types.GenerateContentResponse
import com.nexters.external.config.AiGeminiContentAnalysisProperties
import com.nexters.external.dto.AutoGeneratedContentDraft
import com.nexters.external.dto.BatchContentAnalysisItem
import com.nexters.external.dto.BatchContentAnalysisResult
import com.nexters.external.dto.BatchContentEvaluationItem
import com.nexters.external.dto.BatchContentEvaluationResult
import com.nexters.external.dto.ContentEvaluationResult
import com.nexters.external.dto.GeminiModel
import com.nexters.external.entity.Content
import com.nexters.external.entity.ContentGenerationAttempt
import com.nexters.external.entity.Summary
import com.nexters.external.exception.AiProcessingException
import com.nexters.external.exception.RateLimitExceededException
import com.nexters.external.repository.CandidateKeywordRepository
import com.nexters.external.repository.ContentGenerationAttemptRepository
import com.nexters.external.repository.ContentKeywordMappingRepository
import com.nexters.external.repository.ReservedKeywordRepository
import com.nexters.external.repository.SummaryRepository
import io.mockk.every
import io.mockk.mockk
import kotlin.test.BeforeTest
import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.test.assertFailsWith
import kotlin.test.assertFalse
import kotlin.test.assertTrue
import java.time.LocalDate

class ContentAnalysisServiceTest {
    private val rateLimiterService = mockk<GeminiRateLimiterService>()
    private val summaryRepository = mockk<SummaryRepository>()
    private val reservedKeywordRepository = mockk<ReservedKeywordRepository>()
    private val candidateKeywordRepository = mockk<CandidateKeywordRepository>(relaxed = true)
    private val contentKeywordMappingRepository = mockk<ContentKeywordMappingRepository>(relaxed = true)
    private val contentGenerationAttemptRepository = mockk<ContentGenerationAttemptRepository>()
    private val responseParser = mockk<ContentAnalysisResponseParser>()

    private lateinit var service: ContentAnalysisService
    private lateinit var properties: AiGeminiContentAnalysisProperties

    private val savedAttempts = mutableListOf<ContentGenerationAttempt>()
    private val savedSummaries = mutableListOf<Summary>()

    @BeforeTest
    fun setUp() {
        properties =
            AiGeminiContentAnalysisProperties().apply {
                minNaturalnessScore = 7
                maxRegenerationAttempts = 1
            }

        savedAttempts.clear()
        savedSummaries.clear()

        every { reservedKeywordRepository.findAll() } returns emptyList()
        every { reservedKeywordRepository.findByNameIn(any()) } returns emptyList()
        every { contentGenerationAttemptRepository.save(any()) } answers {
            firstArg<ContentGenerationAttempt>().also(savedAttempts::add)
        }
        every { summaryRepository.save(any()) } answers {
            firstArg<Summary>().also(savedSummaries::add)
        }
        every { summaryRepository.findByContent(any()) } returns emptyList()

        val modelFallbackExecutor = GeminiModelFallbackExecutor()
        val promptFactory = ContentAnalysisPromptFactory()
        val legacyKeywordAnalysisService =
            LegacyKeywordAnalysisService(
                modelFallbackExecutor = modelFallbackExecutor,
                rateLimiterService = rateLimiterService,
                responseParser = responseParser,
            )
        val pipelineService =
            AutoContentAnalysisPipelineService(
                rateLimiterService = rateLimiterService,
                contentAnalysisProperties = properties,
                promptFactory = promptFactory,
                responseParser = responseParser,
                modelFallbackExecutor = modelFallbackExecutor,
            )
        val persistenceService =
            ContentAnalysisPersistenceService(
                summaryRepository = summaryRepository,
                contentGenerationAttemptRepository = contentGenerationAttemptRepository,
            )
        val keywordService =
            ContentKeywordService(
                reservedKeywordRepository = reservedKeywordRepository,
                candidateKeywordRepository = candidateKeywordRepository,
                contentKeywordMappingRepository = contentKeywordMappingRepository,
            )

        service =
            ContentAnalysisService(
                autoContentAnalysisPipelineService = pipelineService,
                legacyKeywordAnalysisService = legacyKeywordAnalysisService,
                contentAnalysisPersistenceService = persistenceService,
                contentKeywordService = keywordService,
            )
    }

    @Test
    fun `accepted on first pass saves one accepted attempt and summary quality`() {
        val content = sampleContent(id = 1L)
        val generationResponse = mockResponse("gen-1")
        val evaluationResponse = mockResponse("eval-1")

        every {
            rateLimiterService.executeAutoGenerationWithRateLimit(any(), GeminiModel.TWO_FIVE_FLASH, content.content)
        } returns generationResponse
        every {
            responseParser.parseAutoGenerationResponse("gen-1", GeminiModel.TWO_FIVE_FLASH)
        } returns AutoGeneratedContentDraft("요약", listOf("자연스러운 헤드라인"), listOf("kotlin"))
        every {
            rateLimiterService.executeAutoEvaluationWithRateLimit(GeminiModel.TWO_FIVE_FLASH, any())
        } returns evaluationResponse
        every {
            responseParser.parseEvaluationResponse("eval-1", GeminiModel.TWO_FIVE_FLASH)
        } returns
            ContentEvaluationResult(
                score = 8,
                reason = "사람이 다듬은 문장처럼 자연스럽습니다.",
                aiLikePatterns = emptyList(),
                recommendedFix = "유지",
                passed = true,
                retryCount = 0,
                usedModel = GeminiModel.TWO_FIVE_FLASH,
            )

        val result = service.analyzeAndSave(content)

        assertEquals(8, result.qualityScore)
        assertTrue(result.passed)
        assertEquals(1, savedAttempts.size)
        assertTrue(savedAttempts.single().accepted)
        assertTrue(savedAttempts.single().passed)
        assertEquals(0, savedAttempts.single().retryCount)
        assertEquals(1, savedSummaries.size)
        assertEquals(8, savedSummaries.single().qualityScore)
        assertEquals("사람이 다듬은 문장처럼 자연스럽습니다.", savedSummaries.single().qualityReason)
        assertEquals(0, savedSummaries.single().retryCount)
    }

    @Test
    fun `below threshold single retry then accept stores failed and accepted attempts`() {
        val content = sampleContent(id = 2L)

        every {
            rateLimiterService.executeAutoGenerationWithRateLimit(any(), GeminiModel.TWO_FIVE_FLASH, content.content)
        } returnsMany listOf(mockResponse("gen-1"), mockResponse("gen-2"))
        every {
            responseParser.parseAutoGenerationResponse("gen-1", GeminiModel.TWO_FIVE_FLASH)
        } returns AutoGeneratedContentDraft("요약1", listOf("헤드라인1"), listOf("kotlin"))
        every {
            responseParser.parseAutoGenerationResponse("gen-2", GeminiModel.TWO_FIVE_FLASH)
        } returns AutoGeneratedContentDraft("요약2", listOf("헤드라인2"), listOf("kotlin"))
        every {
            rateLimiterService.executeAutoEvaluationWithRateLimit(GeminiModel.TWO_FIVE_FLASH, any())
        } returnsMany listOf(mockResponse("eval-1"), mockResponse("eval-2"))
        every {
            responseParser.parseEvaluationResponse("eval-1", GeminiModel.TWO_FIVE_FLASH)
        } returns
            ContentEvaluationResult(
                score = 5,
                reason = "표현이 너무 AI스럽습니다.",
                aiLikePatterns = listOf("상투적 표현"),
                recommendedFix = "대상을 더 구체화하세요.",
                passed = false,
                retryCount = 0,
                usedModel = GeminiModel.TWO_FIVE_FLASH,
            )
        every {
            responseParser.parseEvaluationResponse("eval-2", GeminiModel.TWO_FIVE_FLASH)
        } returns
            ContentEvaluationResult(
                score = 8,
                reason = "재생성 후 훨씬 자연스럽습니다.",
                aiLikePatterns = emptyList(),
                recommendedFix = "유지",
                passed = true,
                retryCount = 1,
                usedModel = GeminiModel.TWO_FIVE_FLASH,
            )

        val result = service.analyzeAndSave(content)

        assertEquals(2, savedAttempts.size)
        assertFalse(savedAttempts.first().accepted)
        assertTrue(savedAttempts.last().accepted)
        assertEquals(0, savedAttempts.first().retryCount)
        assertEquals(1, savedAttempts.last().retryCount)
        assertEquals(8, result.qualityScore)
        assertEquals(1, result.retryCount)
        assertTrue(result.passed)
        assertEquals(8, savedSummaries.single().qualityScore)
    }

    @Test
    fun `batch partial retry retries only failing item individually`() {
        val content1 = sampleContent(id = 10L, body = "첫 번째 콘텐츠")
        val content2 = sampleContent(id = 11L, body = "두 번째 콘텐츠")

        every {
            rateLimiterService.executeBatchAutoGenerationWithRateLimit(any(), GeminiModel.TWO_FIVE_FLASH, any())
        } returns mockResponse("batch-gen")
        every {
            responseParser.parseBatchAutoGenerationResponse("batch-gen", GeminiModel.TWO_FIVE_FLASH)
        } returns
            BatchContentAnalysisResult(
                results =
                    mapOf(
                        "10" to BatchContentAnalysisItem("10", "요약1", listOf("헤드라인1"), listOf("kotlin")),
                        "11" to BatchContentAnalysisItem("11", "요약2", listOf("헤드라인2"), listOf("redis")),
                    ),
                usedModel = GeminiModel.TWO_FIVE_FLASH,
            )
        every {
            rateLimiterService.executeBatchAutoEvaluationWithRateLimit(GeminiModel.TWO_FIVE_FLASH, any())
        } returns mockResponse("batch-eval")
        every {
            responseParser.parseBatchEvaluationResponse("batch-eval", GeminiModel.TWO_FIVE_FLASH)
        } returns
            BatchContentEvaluationResult(
                results =
                    mapOf(
                        "10" to
                            BatchContentEvaluationItem(
                                contentId = "10",
                                score = 8,
                                reason = "좋습니다.",
                                aiLikePatterns = emptyList(),
                                recommendedFix = "유지",
                                passed = true,
                                retryCount = 0,
                            ),
                        "11" to
                            BatchContentEvaluationItem(
                                contentId = "11",
                                score = 4,
                                reason = "표현이 뻔합니다.",
                                aiLikePatterns = listOf("클릭베이트"),
                                recommendedFix = "핵심 대상을 드러내세요.",
                                passed = false,
                                retryCount = 0,
                            ),
                    ),
                usedModel = GeminiModel.TWO_FIVE_FLASH,
            )
        every {
            rateLimiterService.executeAutoGenerationWithRateLimit(any(), GeminiModel.TWO_FIVE_FLASH, content2.content)
        } returns mockResponse("retry-gen")
        every {
            responseParser.parseAutoGenerationResponse("retry-gen", GeminiModel.TWO_FIVE_FLASH)
        } returns AutoGeneratedContentDraft("재생성 요약", listOf("재생성 헤드라인"), listOf("redis"))
        every {
            rateLimiterService.executeAutoEvaluationWithRateLimit(GeminiModel.TWO_FIVE_FLASH, any())
        } returns mockResponse("retry-eval")
        every {
            responseParser.parseEvaluationResponse("retry-eval", GeminiModel.TWO_FIVE_FLASH)
        } returns
            ContentEvaluationResult(
                score = 8,
                reason = "재생성 후 자연스럽습니다.",
                aiLikePatterns = emptyList(),
                recommendedFix = "유지",
                passed = true,
                retryCount = 1,
                usedModel = GeminiModel.TWO_FIVE_FLASH,
            )

        val result = service.analyzeBatchAndSave(listOf(content1, content2))

        assertEquals(2, result.size)
        assertEquals(0, result.getValue("10").retryCount)
        assertEquals(1, result.getValue("11").retryCount)
        assertEquals(3, savedAttempts.size)
        assertEquals(1, savedAttempts.count { it.content.id == 10L })
        assertEquals(2, savedAttempts.count { it.content.id == 11L })
        assertTrue(savedAttempts.last().accepted)
    }

    @Test
    fun `exhausted retry count accepts last low-score result`() {
        val content = sampleContent(id = 3L)

        every {
            rateLimiterService.executeAutoGenerationWithRateLimit(any(), GeminiModel.TWO_FIVE_FLASH, content.content)
        } returnsMany listOf(mockResponse("gen-1"), mockResponse("gen-2"))
        every {
            responseParser.parseAutoGenerationResponse(any(), GeminiModel.TWO_FIVE_FLASH)
        } returnsMany
            listOf(
                AutoGeneratedContentDraft("요약1", listOf("헤드라인1"), listOf("kotlin")),
                AutoGeneratedContentDraft("요약2", listOf("헤드라인2"), listOf("kotlin")),
            )
        every {
            rateLimiterService.executeAutoEvaluationWithRateLimit(GeminiModel.TWO_FIVE_FLASH, any())
        } returnsMany listOf(mockResponse("eval-1"), mockResponse("eval-2"))
        every {
            responseParser.parseEvaluationResponse("eval-1", GeminiModel.TWO_FIVE_FLASH)
        } returns
            ContentEvaluationResult(
                score = 5,
                reason = "여전히 상투적입니다.",
                aiLikePatterns = listOf("상투적 표현"),
                recommendedFix = "더 구체적인 주체를 넣으세요.",
                passed = false,
                retryCount = 0,
                usedModel = GeminiModel.TWO_FIVE_FLASH,
            )
        every {
            responseParser.parseEvaluationResponse("eval-2", GeminiModel.TWO_FIVE_FLASH)
        } returns
            ContentEvaluationResult(
                score = 6,
                reason = "조금 나아졌지만 기준 미달입니다.",
                aiLikePatterns = listOf("어색한 리듬"),
                recommendedFix = "핵심 사건을 더 선명하게 쓰세요.",
                passed = false,
                retryCount = 1,
                usedModel = GeminiModel.TWO_FIVE_FLASH,
            )

        val result = service.analyzeAndSave(content)

        assertFalse(result.passed)
        assertEquals(1, result.retryCount)
        assertEquals(2, savedAttempts.size)
        assertTrue(savedAttempts.last().accepted)
        assertFalse(savedAttempts.last().passed)
        assertEquals(6, savedSummaries.single().qualityScore)
    }

    @Test
    fun `all rate limited generation throws rate limit exception`() {
        every {
            rateLimiterService.executeAutoGenerationWithRateLimit(any(), GeminiModel.TWO_FIVE_FLASH, any())
        } throws RateLimitExceededException("limited", "RPM", GeminiModel.TWO_FIVE_FLASH.modelName)
        every {
            rateLimiterService.executeAutoGenerationWithRateLimit(any(), GeminiModel.TWO_FIVE_FLASH_LITE, any())
        } throws RateLimitExceededException("limited", "RPM", GeminiModel.TWO_FIVE_FLASH_LITE.modelName)

        assertFailsWith<RateLimitExceededException> {
            service.analyzeContent("예시 콘텐츠", emptyList())
        }
    }

    @Test
    fun `parse failure across all models throws ai processing exception`() {
        val generationResponse = mockResponse("bad-gen")

        every {
            rateLimiterService.executeAutoGenerationWithRateLimit(any(), GeminiModel.TWO_FIVE_FLASH, any())
        } returns generationResponse
        every {
            rateLimiterService.executeAutoGenerationWithRateLimit(any(), GeminiModel.TWO_FIVE_FLASH_LITE, any())
        } returns generationResponse
        every {
            responseParser.parseAutoGenerationResponse("bad-gen", GeminiModel.TWO_FIVE_FLASH)
        } returns null
        every {
            responseParser.parseAutoGenerationResponse("bad-gen", GeminiModel.TWO_FIVE_FLASH_LITE)
        } returns null

        assertFailsWith<AiProcessingException> {
            service.analyzeContent("예시 콘텐츠", emptyList())
        }
    }

    private fun sampleContent(
        id: Long,
        body: String = "Kotlin과 Redis를 다루는 본문",
    ): Content =
        Content(
            id = id,
            title = "샘플 제목",
            content = body,
            newsletterName = "newsletter",
            originalUrl = "https://example.com/$id",
            publishedAt = LocalDate.of(2026, 4, 2),
        )

    private fun mockResponse(text: String): GenerateContentResponse {
        val response = mockk<GenerateContentResponse>()
        every { response.text() } returns text
        return response
    }
}
